def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = 1 / j
            term = (ratio ** j) * weight
            if j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        remaining = capacity - item
        if remaining < capacity * 0.1:
            score *= 1.7
            for k in range(1, 4):
                score += (remaining / capacity) ** k * (0.5 / k)
        elif remaining > capacity * 0.5:
            score *= 0.6
            for k in range(1, 3):
                score -= (remaining / capacity) ** (2 * k) * (0.3 / k)
        else:
            for k in range(1, 5):
                if (k + i) % 2 == 0:
                    score += (ratio * k) / (remaining + 1)
                else:
                    score -= (ratio * k) / (remaining + 1)
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
